4	Engineer	Engineers are masters of technology, building and modifying equipment, vehicles, drones, and robots. They combine technical expertise with combat capability.	8	Intelligence	["Constitution","Intelligence"]	["Light armor","Medium armor"]	["Simple weapons","Sidearms"]	["Computers","Investigation","Life Science","Mechanics","Medicine","Physical Science"]	2	{"1":[{"name":"Hacking","description":"You gain the ability to run engineer hacks — technical programs that manipulate devices and machinery."},{"name":"Technical Proficiency","description":"You can add your proficiency bonus to any Mechanics check to repair or modify equipment."}],"2":[{"name":"Tool Expertise","description":"Your proficiency bonus is doubled for any ability check that uses your tool proficiencies."}],"3":[{"name":"Archetype","description":"Choose your Engineer archetype: Gadgeteer, Gearhead, or Roboticist."}],"4":[{"name":"Ability Score Improvement","description":"Increase one ability score by 2, or two ability scores by 1 each. Alternatively, choose a feat."}],"5":[{"name":"Enhanced Engineering","description":"Your engineering hacks become more potent, gaining additional effects at higher levels."}],"8":[{"name":"Ability Score Improvement","description":"Increase one ability score by 2, or two ability scores by 1 each. Alternatively, choose a feat."}],"12":[{"name":"Ability Score Improvement","description":"Increase one ability score by 2, or two ability scores by 1 each. Alternatively, choose a feat."}],"16":[{"name":"Ability Score Improvement","description":"Increase one ability score by 2, or two ability scores by 1 each. Alternatively, choose a feat."}],"19":[{"name":"Ability Score Improvement","description":"Increase one ability score by 2, or two ability scores by 1 each. Alternatively, choose a feat."}],"20":[{"name":"Master Engineer","description":"You reach the pinnacle of engineering, creating masterwork devices and machines."}]}	[{"name":"Gadgeteer","description":"Gadgeteers create specialized tools and devices that give them an edge in and out of combat."},{"name":"Gearhead","description":"Gearheads specialize in vehicles and heavy machinery, becoming expert pilots and mechanics."},{"name":"Roboticist","description":"Roboticists build and control robots, deploying mechanical allies to assist in combat and exploration."}]
